# Load AGMH 2019 data for testing
agmh_data = locals()['var_functions.query_db:30']

if isinstance(agmh_data, str) and agmh_data.endswith('.json'):
    with open(agmh_data, 'r') as f:
        agmh_trades = json.load(f)
